// Add to packages/data/prisma/schema.prisma (near Giveaway/GiveawayEntry —
// same "round + per-user rows" shape, tenantId+chatId scoping, BigInt telegram ids):

model SpeedRound {
  id           String   @id @default(cuid())
  tenantId     String
  chatId       String
  question     String
  answer       String
  status       String   @default("open") // "open" | "closed"
  startedAt    DateTime @default(now())
  closesAt     DateTime
  winnerUserId BigInt?
  createdBy    BigInt?
  createdAt    DateTime @default(now())
  updatedAt    DateTime @updatedAt

  submissions SpeedRoundAnswer[]

  @@index([tenantId, chatId, status])
  @@map("speed_rounds")
}

model SpeedRoundAnswer {
  id         String   @id @default(cuid())
  roundId    String
  userId     BigInt
  correct    Boolean
  answeredAt DateTime @default(now())

  round SpeedRound @relation(fields: [roundId], references: [id], onDelete: Cascade)

  @@unique([roundId, userId])
  @@index([roundId])
  @@map("speed_round_answers")
}

