      {
        name: "speed-game.command",
        handle: ({ context, update }) =>
          this.handleSpeedGameCommand(context, update),
      },

// ============================================================
// 6) New private static constant — put it anywhere in the class's static-field
//    area, e.g. right next to `private static readonly ADMIN_CACHE_TTL_MS`
//    (~line 2004):
// ============================================================
  private static readonly SPEED_GAME_WINDOW_MS = 20_000;

  private static normalizeSpeedAnswer(text: string): string {
    return text
      .normalize("NFD")
      .replace(/[̀-ͯ]/gu, "")
      .trim()
      .toLowerCase();
  }

// ============================================================
// 7) New handler methods — add as their own methods anywhere among the other
//    private handleXCommand methods (e.g. right after handleGiveawayJoin,
//    ~line 7705, to sit next to the other single-active-item game/contest
//    handler it most resembles):
// ============================================================

  private async handleSpeedGameCommand(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    const name = update.command?.name;
    if (
      name !== "velocidad" &&
      name !== "responder" &&
      name !== "cerrarvelocidad"
    ) {
      return null;
    }

    if (!context.chatId) {
      return { text: "El juego de velocidad se juega dentro de un grupo." };
    }

    const args = update.command?.args ?? [];
    const nowMs = update.receivedAt.getTime();

    if (name === "velocidad") {
      if (!(await this.isActorAdmin(context, update))) {
        return { text: "Solo el staff puede iniciar una ronda de velocidad." };
      }

      const [questionRaw, answerRaw] = args.join(" ").split("|");
      const question = questionRaw?.trim();
      const answer = answerRaw?.trim();
      if (!question || !answer) {
        return { text: "Uso: /velocidad <pregunta>|<respuesta>" };
      }

      const existing = await this.speedGameRepository.getOpenRound(
        context.tenantId,
        context.chatId,
      );
      if (existing) {
        if (existing.closesAt.getTime() > nowMs) {
          return {
            text: "⏱️ Ya hay una ronda de velocidad abierta. Espera a que se cierre o usa /cerrarvelocidad.",
          };
        }
        // Expired but nobody triggered the lazy close yet — close it first
        // so we never have two "open" rounds for the same chat at once.
        await this.speedGameRepository.closeRound(existing.id);
      }

      const startedAt = new Date(nowMs);
      const closesAt = new Date(
        nowMs + BotUpdateService.SPEED_GAME_WINDOW_MS,
      );
      await this.speedGameRepository.createRound(
        context.tenantId,
        context.chatId,
        question,
        answer,
        startedAt,
        closesAt,
        update.user.userId,
      );

      const seconds = Math.round(BotUpdateService.SPEED_GAME_WINDOW_MS / 1000);
      return {
        text: `⚡ *Ronda de velocidad* ⚡\n${question}\n\nResponde con /responder <tu respuesta>. Tienes ${seconds}s.`,
        parseMode: "Markdown",
      };
    }

    if (name === "cerrarvelocidad") {
      if (!(await this.isActorAdmin(context, update))) {
        return { text: "Solo el staff puede cerrar la ronda de velocidad." };
      }
      const round = await this.speedGameRepository.getOpenRound(
        context.tenantId,
        context.chatId,
      );
      if (!round) {
        return { text: "No hay ninguna ronda de velocidad abierta." };
      }
      return this.announceSpeedGameClose(round.id, round.question);
    }

    // name === "responder"
    if (!update.user.userId) {
      return null;
    }

    const round = await this.speedGameRepository.getOpenRound(
      context.tenantId,
      context.chatId,
    );
    if (!round) {
      return {
        text: "No hay ninguna ronda de velocidad abierta. Usa /velocidad para iniciar una.",
      };
    }

    if (round.closesAt.getTime() <= nowMs) {
      // Window already elapsed: close it now instead of accepting a late
      // answer, so the group always gets a winner announcement eventually
      // even if nobody used /cerrarvelocidad.
      return this.announceSpeedGameClose(round.id, round.question);
    }

    const answerText = args.join(" ").trim();
    if (!answerText) {
      return { text: "Uso: /responder <tu respuesta>" };
    }

    const correct =
      BotUpdateService.normalizeSpeedAnswer(answerText) ===
      BotUpdateService.normalizeSpeedAnswer(round.answer);
    const accepted = await this.speedGameRepository.submitAnswer(
      round.id,
      update.user.userId,
      new Date(nowMs),
      correct,
    );

    if (!accepted) {
      return { text: "Ya enviaste tu respuesta para esta ronda." };
    }

    return {
      text: "📨 Respuesta registrada. Espera al cierre de la ronda para ver quién ganó.",
    };
  }

  private async announceSpeedGameClose(
    roundId: string,
    question: string,
  ): Promise<BotReply> {
    const { ranked, winnerUserId } =
      await this.speedGameRepository.closeRound(roundId);

    if (!winnerUserId) {
      return {
        text: `⏱️ Ronda de velocidad cerrada: "${question}"\nNadie acertó a tiempo.`,
      };
    }

    const podium = ranked
      .slice(0, 3)
      .map((entry, index) => `${index + 1}. ${entry.userId} (${entry.ms}ms)`)
      .join("\n");

    return {
      text: `🏆 Ronda de velocidad cerrada: "${question}"\nGanador: ${winnerUserId}\n\n${podium}`,
    };
  }
